const data = $input.first().json;
const product = {
  name: String(data.name || '').trim().slice(0, 120),
  description: String(data.description || '').trim(),
  price: Number(data.price || 0),
  stock: Math.max(0, Number(data.stock || 0)),
  sku: String(data.sku || '').trim(),
  images: Array.isArray(data.images) ? data.images.filter(Boolean) : [],
  category: String(data.category || '').trim(),
  attributes: data.attributes || {},
  weight: data.weight ? Number(data.weight) : undefined,
  dimensions: data.dimensions || {}
};
return [{ json: product }];

const product = $input.first().json;
// TODO: Call Shopee Open Platform category/attribute endpoints and map exact category_id + attribute list.
return [{ json: { ...product, shopee_category_id: product.shopee_category_id || product.category_id || 0, shopee_attributes: product.attributes || {} } }];

const data = $input.first().json;
const errors = [];
if (!data.name) errors.push('name is required');
if (!data.description) errors.push('description is required');
if (Number(data.price) <= 0) errors.push('price must be positive');
if (Number(data.stock) < 0) errors.push('stock must be zero or positive');
if (!data.sku) errors.push('sku is required');
if (!Array.isArray(data.images) || data.images.length === 0) errors.push('images are required');
if (!data.category) errors.push('category is required');
if (errors.length) throw new Error(`Invalid Shopee product: ${errors.join(', ')}`);
return [{ json: data }];

const result = $input.first().json;
// TODO: Persist Shopee item_id/update status to source system.
return [{ json: { channel: 'shopee', ok: true, result, saved_at: new Date().toISOString() } }];
